INSERT INTO `posts` VALUES (1,2,1,'Brasil bate recorde e eletrificados já são quase 20% do mercado','brasil-recorde-eletrificados-20-mercado','Participação dos eletrificados chega a 19,2% em maio, com modelos compactos puxando os elétricos.','<p>O cenário da mobilidade elétrica no Brasil segue em aceleração, e a notícia sobre \"Brasil bate recorde e eletrificados já são quase 20% do mercado\" reforça a transformação do setor automotivo.</p><p>Analistas apontam que a combinação de incentivos, novos lançamentos e maior oferta de recarga tem impulsionado a adoção de veículos eletrificados nas principais regiões do país.</p><p>Para o consumidor, a disputa entre montadoras tradicionais e novos players internacionais tende a ampliar opções, reduzir prazos de entrega e estimular inovações em baterias, software e experiência de condução.</p><p>Acompanhe o Auto News para entender como essas mudanças impactam preços, seminovos e a infraestrutura de recarga no Brasil.</p>','https://images.unsplash.com/photo-1593941707882-a5bba14938c7?w=1200&h=675&fit=crop','published',0,1,'2026-05-11 17:56:31','2026-05-19 17:55:24','2026-05-19 17:56:31',NULL),(2,1,1,'BYD sofre falta de baterias após boom dos elétricos de recarga rápida','byd-falta-baterias-recarga-rapida','Demanda por modelos de entrada pressiona cadeia de suprimentos e amplia filas de entrega.','<p>O cenário da mobilidade elétrica no Brasil segue em aceleração, e a notícia sobre \"BYD sofre falta de baterias após boom dos elétricos de recarga rápida\" reforça a transformação do setor automotivo.</p><p>Analistas apontam que a combinação de incentivos, novos lançamentos e maior oferta de recarga tem impulsionado a adoção de veículos eletrificados nas principais regiões do país.</p><p>Para o consumidor, a disputa entre montadoras tradicionais e novos players internacionais tende a ampliar opções, reduzir prazos de entrega e estimular inovações em baterias, software e experiência de condução.</p><p>Acompanhe o Auto News para entender como essas mudanças impactam preços, seminovos e a infraestrutura de recarga no Brasil.</p>','https://images.unsplash.com/photo-1617788138017-80ad40651399?w=1200&h=675&fit=crop','published',0,1,'2026-05-12 17:56:31','2026-05-19 17:55:24','2026-05-19 17:56:31',NULL),(3,2,1,'Chinesas já começam a mudar o mercado de seminovos no Brasil','chinesas-mercado-seminovos-brasil','Marcas asiáticas aceleram revenda e alteram a dinâmica de precificação dos elétricos usados.','<p>O cenário da mobilidade elétrica no Brasil segue em aceleração, e a notícia sobre \"Chinesas já começam a mudar o mercado de seminovos no Brasil\" reforça a transformação do setor automotivo.</p><p>Analistas apontam que a combinação de incentivos, novos lançamentos e maior oferta de recarga tem impulsionado a adoção de veículos eletrificados nas principais regiões do país.</p><p>Para o consumidor, a disputa entre montadoras tradicionais e novos players internacionais tende a ampliar opções, reduzir prazos de entrega e estimular inovações em baterias, software e experiência de condução.</p><p>Acompanhe o Auto News para entender como essas mudanças impactam preços, seminovos e a infraestrutura de recarga no Brasil.</p>','https://images.unsplash.com/photo-1552519507-da3b142c6e3d?w=1200&h=675&fit=crop','published',0,1,'2026-05-13 17:56:31','2026-05-19 17:55:24','2026-05-19 19:04:51',NULL),(4,1,1,'Volkswagen volta atrás nos elétricos: ID.3 recupera botões físicos','volkswagen-id3-botoes-fisicos','Após críticas, hatch elétrico recebe comandos tradicionais e melhora acabamento.','<p>O cenário da mobilidade elétrica no Brasil segue em aceleração, e a notícia sobre \"Volkswagen volta atrás nos elétricos: ID.3 recupera botões físicos\" reforça a transformação do setor automotivo.</p><p>Analistas apontam que a combinação de incentivos, novos lançamentos e maior oferta de recarga tem impulsionado a adoção de veículos eletrificados nas principais regiões do país.</p><p>Para o consumidor, a disputa entre montadoras tradicionais e novos players internacionais tende a ampliar opções, reduzir prazos de entrega e estimular inovações em baterias, software e experiência de condução.</p><p>Acompanhe o Auto News para entender como essas mudanças impactam preços, seminovos e a infraestrutura de recarga no Brasil.</p>','https://images.unsplash.com/photo-1619767886555-ef6d06b37b77?w=1200&h=675&fit=crop','published',0,0,'2026-05-14 17:56:31','2026-05-19 17:55:24','2026-05-19 17:56:31',NULL),(5,4,1,'Stellantis prepara carro elétrico barato para rivalizar com BYD','stellantis-eletrico-barato-byd','Projeto de compacto elétrico europeu começa em 2028 e pode usar tecnologia chinesa.','<p>O cenário da mobilidade elétrica no Brasil segue em aceleração, e a notícia sobre \"Stellantis prepara carro elétrico barato para rivalizar com BYD\" reforça a transformação do setor automotivo.</p><p>Analistas apontam que a combinação de incentivos, novos lançamentos e maior oferta de recarga tem impulsionado a adoção de veículos eletrificados nas principais regiões do país.</p><p>Para o consumidor, a disputa entre montadoras tradicionais e novos players internacionais tende a ampliar opções, reduzir prazos de entrega e estimular inovações em baterias, software e experiência de condução.</p><p>Acompanhe o Auto News para entender como essas mudanças impactam preços, seminovos e a infraestrutura de recarga no Brasil.</p>','https://images.unsplash.com/photo-1618843479313-40f8afb4b4d8?w=1200&h=675&fit=crop','published',0,0,'2026-05-15 17:56:31','2026-05-19 17:55:24','2026-05-19 17:56:31',NULL),(6,5,1,'Bateria sólida segue funcionando após ser cortada, mas há um porém','bateria-solida-funciona-apos-corte','Startup chinesa mostrou célula operando após teste extremo, mas adoção em carros ainda levará tempo.','<p>O cenário da mobilidade elétrica no Brasil segue em aceleração, e a notícia sobre \"Bateria sólida segue funcionando após ser cortada, mas há um porém\" reforça a transformação do setor automotivo.</p><p>Analistas apontam que a combinação de incentivos, novos lançamentos e maior oferta de recarga tem impulsionado a adoção de veículos eletrificados nas principais regiões do país.</p><p>Para o consumidor, a disputa entre montadoras tradicionais e novos players internacionais tende a ampliar opções, reduzir prazos de entrega e estimular inovações em baterias, software e experiência de condução.</p><p>Acompanhe o Auto News para entender como essas mudanças impactam preços, seminovos e a infraestrutura de recarga no Brasil.</p>','https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=1200&h=675&fit=crop','published',1,0,'2026-05-16 17:56:31','2026-05-19 17:55:24','2026-05-19 17:56:31',NULL),(7,4,1,'Porsche Cayenne EV estreia no Brasil com preço de até R$ 1,4 milhão','porsche-cayenne-ev-brasil','SUV elétrico aparece no configurador brasileiro antes do lançamento europeu.','<p>O cenário da mobilidade elétrica no Brasil segue em aceleração, e a notícia sobre \"Porsche Cayenne EV estreia no Brasil com preço de até R$ 1,4 milhão\" reforça a transformação do setor automotivo.</p><p>Analistas apontam que a combinação de incentivos, novos lançamentos e maior oferta de recarga tem impulsionado a adoção de veículos eletrificados nas principais regiões do país.</p><p>Para o consumidor, a disputa entre montadoras tradicionais e novos players internacionais tende a ampliar opções, reduzir prazos de entrega e estimular inovações em baterias, software e experiência de condução.</p><p>Acompanhe o Auto News para entender como essas mudanças impactam preços, seminovos e a infraestrutura de recarga no Brasil.</p>','https://images.unsplash.com/photo-1503376780353-7e6692767b70?w=1200&h=675&fit=crop','published',1,0,'2026-05-17 17:56:31','2026-05-19 17:55:24','2026-05-19 17:56:31',NULL),(8,6,1,'Brasil ganha órgão federal dedicado a carros elétricos e recarga','brasil-orgao-carros-eletricos-recarga','Novo departamento no MME cuidará de recarga, baterias e integração dos elétricos à rede elétrica.','<p>O cenário da mobilidade elétrica no Brasil segue em aceleração, e a notícia sobre \"Brasil ganha órgão federal dedicado a carros elétricos e recarga\" reforça a transformação do setor automotivo.</p><p>Analistas apontam que a combinação de incentivos, novos lançamentos e maior oferta de recarga tem impulsionado a adoção de veículos eletrificados nas principais regiões do país.</p><p>Para o consumidor, a disputa entre montadoras tradicionais e novos players internacionais tende a ampliar opções, reduzir prazos de entrega e estimular inovações em baterias, software e experiência de condução.</p><p>Acompanhe o Auto News para entender como essas mudanças impactam preços, seminovos e a infraestrutura de recarga no Brasil.</p>','https://images.unsplash.com/photo-1544636331-e26879cd4d9b?w=1200&h=675&fit=crop','published',0,0,'2026-05-18 17:56:31','2026-05-19 17:55:24','2026-05-19 17:56:31',NULL),(9,5,1,'Sunt veritatis consequatur voluptatem laboriosam eveniet','sunt-veritatis-consequatur-voluptatem-laboriosam-eveniet-6243','In ut deleniti occaecati vel accusantium. Repellat praesentium quod earum voluptatum tempore at sint est.','<p>Et et numquam ea alias sed cum asperiores provident. Dolor cum sint animi consequatur ratione. Quia voluptatem et suscipit aut molestiae dolores ipsam. Corrupti et molestiae vel iure.</p><p>Itaque nobis id veritatis et iste eaque. Excepturi maxime et nisi. Consectetur voluptatem sit culpa aliquid veritatis aspernatur. Beatae quis est dolorum consequatur reiciendis vel excepturi. Perspiciatis inventore qui ut. Cupiditate odio velit quia numquam.</p><p>Odio cumque ea qui sint est. Qui aspernatur impedit possimus fuga accusantium natus. Omnis accusamus ipsum et rem impedit necessitatibus dolorem. Non dolor quam tempore aut. Numquam praesentium cupiditate harum esse enim. Qui velit eveniet rerum pariatur. Quaerat eos dignissimos consequatur velit sit reprehenderit. Autem alias repudiandae et magni dicta cum hic.</p><p>Totam dolore 